        },
        {
          "questionText": "What specific device is used to measure how much a component opposes the flow of electricity?",
          "answerGuidance": [
            "Ohmmeter",
            "Measures resistance",
            "Measures in Ohms"
          ]
        }
      ],
      "deeperQuestionText": "Why must a circuit be isolated and confirmed as 'dead' before using an ohmmeter to measure a component?",
      "deeperAnswerGuidance": [
        "To prevent damage to the instrument",
        "To ensure an accurate reading without external voltage interference",
        "Because the ohmmeter provides its own internal power for the test",
        "Live voltage can cause false readings or blow the meter fuse"
      ],
      "hint": "Focus on the unit being measured: Amps use Ammeters, Volts use Voltmeters, and Ohms use Ohmmeters."
    },
