      "title": "Measuring Power and Energy",
      "basicQuestions": [
        {
          "questionText": "Which instrument is used to measure the instantaneous rate at which electrical energy is being used?",
          "answerGuidance": [
            "Wattmeter",
            "Measures power",
            "Measures in Watts"
          ]
        },
        {
          "questionText": "What is the specific name for the device used to track the total cumulative energy consumed over a period of time?",
          "answerGuidance": [
            "Energy Meter",
            "kWh meter",
            "Measures total energy consumption"
          ]
        },
        {
          "questionText": "In what unit does an energy meter record the total 'billable' work done by an electrical system?",
          "answerGuidance": [
            "Kilowatt-hours",
            "kWh",
            "Total energy units"
          ]
        }
      ],
      "deeperQuestionText": "How does the function of a wattmeter differ from that of an energy meter when assessing a heating system?",
      "deeperAnswerGuidance": [
        "A wattmeter shows the current rate of power usage at that exact moment",
        "An energy meter shows the total amount of energy used over a duration",
        "The wattmeter checks if the heater is running at its designed capacity",
        "The energy meter is used to calculate the cost of running the heater over time"
      ],
      "hint": "Think of a car: a Wattmeter is like the speedometer (current speed), while an Energy Meter is like the odometer (total distance traveled)."
    }
  ]
}

